+/// Per-theme contrast metrics used by tests and harnesses.
+#[derive(Debug, Clone, Copy, PartialEq)]
+pub struct ThemeContrastMetric {
+    pub theme: ThemeId,
+    pub tab_active: f64,
+    pub tab_inactive: f64,
+    pub status: f64,
+    pub help: f64,
+    pub key_hint: f64,
